125	export function validate({
126		envConfig,
127	}: {
128		envConfig: Record<string, unknown>;
129	}): EnvironmentVariables {
130		const validatedConfig = plainToInstance(EnvironmentVariables, envConfig, {
131			enableImplicitConversion: true,
132		});
133	
134		const errors = validateSync(validatedConfig, {
135			skipMissingProperties: false,
136			forbidUnknownValues: true,
137			stopAtFirstError: true,
138			forbidNonWhitelisted: true,
139		});
140	
141		if (errors.length > 0) {
142			Logger.error('Config validation error', errors);
143			throw new Error(errors.toString());
144		}
145	
146		return validatedConfig;
147	}
