45	export const loadEnvVariables = (): ConfigFactory[] => {
46		if (isStagingEnv() || isProdEnv()) {
47			validate({ envConfig: getEnvVariables() });
48			return [getEnvVariables];
49		}
50	
51		const envFilePath = path.resolve(process.cwd(), getEnvFile());
52	
53		if (!fs.existsSync(envFilePath)) {
54			if (isDevEnv()) {
55				throw new Error(`Env file not found: ${envFilePath}`);
56			}
57			return [() => ({})];
58		}
59	
60		const envConfig = dotenv.parse(fs.readFileSync(envFilePath));
61	
62		validate({ envConfig });
63	
64		return [() => envConfig];
65	};
